from __future__ import annotations


def validate_intake(payload, optional_fields=None):
    if not isinstance(payload.get('patient_id'), str) or payload.get('patient_id') == '':
        raise ValueError('patient_id')
    if not isinstance(payload.get('age'), int) or payload.get('age') < 0:
        raise ValueError('age')
    if not isinstance(payload.get('symptoms'), list) or any(not isinstance(item, str) for item in payload.get('symptoms')):
        raise ValueError('symptoms')
    out = {'patient_id': payload['patient_id'], 'age': payload['age'], 'symptoms': list(payload['symptoms'])}
    for field, validator in (optional_fields or {}).items():
        if field in payload:
            if not validator(payload[field]):
                raise ValueError(field)
            out[field] = payload[field]
    return out

